# Utility implementations module
# Tests: Class implementing multiple interfaces, struct usage from other module,
# cross-module inheritance, static helper methods

from base_types import Point, LogLevel
from contracts import ILogger, IFormatter, IStatsCollector

class ConsoleLogger(ILogger):
    min_level: LogLevel

    def __init__(self, min_level: LogLevel):
        self.min_level = min_level

    def log(self, level: LogLevel, message: str) -> None:
        if level >= self.min_level:
            level_str: str = "UNKNOWN"
            if level == LogLevel.DEBUG:
                level_str = "DEBUG"
            elif level == LogLevel.INFO:
                level_str = "INFO"
            elif level == LogLevel.WARNING:
                level_str = "WARN"
            elif level == LogLevel.ERROR:
                level_str = "ERROR"
            print(f"[{level_str}] {message}")

class FloatFormatter(IFormatter):
    precision: int

    def __init__(self, precision: int):
        self.precision = precision

    def format_value(self, value: float) -> str:
        # Format with specified precision using f-string
        if self.precision == 0:
            return f"{value:.0f}"
        elif self.precision == 1:
            return f"{value:.1f}"
        elif self.precision == 2:
            return f"{value:.2f}"
        elif self.precision == 3:
            return f"{value:.3f}"
        elif self.precision == 4:
            return f"{value:.4f}"
        else:
            return f"{value:.2f}"

class StatsCollector(IStatsCollector):
    values: list[float]

    def __init__(self):
        self.values = []

    def record(self, value: float) -> None:
        self.values.append(value)

    def get_average(self) -> float:
        if len(self.values) == 0:
            return 0.0
        total: float = 0.0
        for v in self.values:
            total += v
        return total / len(self.values)

    def get_count(self) -> int:
        return len(self.values)

class GeometryUtils:
    @staticmethod
    def calculate_centroid(points: list[Point]) -> Point:
        if len(points) == 0:
            return Point(0.0, 0.0)
        sum_x: float = 0.0
        sum_y: float = 0.0
        for p in points:
            sum_x += p.x
            sum_y += p.y
        return Point(sum_x / len(points), sum_y / len(points))
